import React, { useState, useEffect } from 'react';
import { db } from '../firebase';
import { collection, getDocs, addDoc, Timestamp } from 'firebase/firestore';

function TeamsManagement() {
  const [players, setPlayers] = useState([]);
  const [teamName, setTeamName] = useState('');
  const [selectedPlayers, setSelectedPlayers] = useState([]);

  useEffect(() => {
    const fetchPlayers = async () => {
      const playersCollection = await getDocs(collection(db, 'players'));
      const playersData = playersCollection.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
      }));
      setPlayers(playersData);
    };
    fetchPlayers();
  }, []);

  const handlePlayerSelect = (player) => {
    if (!selectedPlayers.includes(player)) {
      setSelectedPlayers([...selectedPlayers, player]);
    }
  };

  const handlePlayerRemove = (playerId) => {
    setSelectedPlayers(selectedPlayers.filter(p => p.id !== playerId));
  };

  const handleCreateTeam = async () => {
    if (teamName.trim() === '' || selectedPlayers.length === 0) {
      alert('Please enter a team name and select players.');
      return;
    }

    try {
      await addDoc(collection(db, 'teams'), {
        name: teamName,
        players: selectedPlayers.map(p => p.id),
        createdAt: Timestamp.now(),
      });
      alert('Team created successfully!');
      setTeamName('');
      setSelectedPlayers([]);
    } catch (error) {
      console.error('Error creating team:', error);
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Teams Management</h1>

      <input
        type="text"
        placeholder="Enter Team Name"
        value={teamName}
        onChange={(e) => setTeamName(e.target.value)}
        style={styles.input}
      />

      <h3 style={styles.subTitle}>Available Players</h3>
      <div style={styles.playersList}>
        {players.map(player => (
          <div key={player.id} style={styles.playerCard}>
            <p>{player.firstName} {player.lastName}</p>
            <button onClick={() => handlePlayerSelect(player)} style={styles.addButton}>Add</button>
          </div>
        ))}
      </div>

      <h3 style={styles.subTitle}>Selected Players</h3>
      <div style={styles.playersList}>
        {selectedPlayers.map(player => (
          <div key={player.id} style={styles.playerCard}>
            <p>{player.firstName} {player.lastName}</p>
            <button onClick={() => handlePlayerRemove(player.id)} style={styles.removeButton}>Remove</button>
          </div>
        ))}
      </div>

      <button onClick={handleCreateTeam} style={styles.button}>Create Team</button>
    </div>
  );
}

const styles = {
  container: { backgroundColor: '#D6F8D6', padding: '20px', fontFamily: "'Press Start 2P', cursive" },
  title: { fontSize: '24px', color: '#293F14' },
  input: { padding: '10px', width: '300px', marginBottom: '20px' },
  subTitle: { marginTop: '20px', fontSize: '18px' },
  playersList: { display: 'flex', flexWrap: 'wrap', gap: '10px' },
  playerCard: { padding: '10px', border: '1px solid #293F14', borderRadius: '8px' },
  addButton: { backgroundColor: '#7FC6A4', padding: '5px 10px' },
  removeButton: { backgroundColor: '#FF4D4D', padding: '5px 10px' },
  button: { padding: '10px 20px', backgroundColor: '#386C0B', color: '#FFF' },
};

export default TeamsManagement;
